<script setup lang="ts">import{onMounted,ref}from"vue";import{useRoute}from"vue-router";import{Building2,MapPin,Phone,ChevronRight}from"lucide-vue-next";import{api,type Department,type Doctor,type Hospital}from"../api";import PageHeader from"../components/PageHeader.vue";import DoctorCard from"../components/DoctorCard.vue";const route=useRoute(),hospital=ref<Hospital>(),departments=ref<Department[]>([]),doctors=ref<Doctor[]>([]);onMounted(async()=>{const id=Number(route.params.id);[hospital.value,departments.value,doctors.value]=await Promise.all([api.hospital(id),api.departments(id),api.doctors({hospitalId:id})])});</script><template><main v-if="hospital"><PageHeader title="医院详情"/><section class="hospital-hero"><span><Building2/></span><div><h1>{{hospital.name}}</h1><p>{{hospital.level}} · {{hospital.type}}</p></div></section><section class="info-card"><p><MapPin/>{{hospital.province}}{{hospital.city}}{{hospital.district}}{{hospital.address}}</p><p v-if="hospital.phone"><Phone/>{{hospital.phone}}</p><small>{{hospital.description||'医院提供在线预约挂号服务。'}}</small></section><section class="block"><header><h2>医院科室</h2></header><div class="department-list"><router-link v-for="d in departments" :key="d.id" :to="`/departments/${d.id}`">{{d.name}}<ChevronRight/></router-link></div></section><section class="recommend"><header><h2>推荐医生</h2></header><DoctorCard v-for="d in doctors" :key="d.id" :doctor="d"/></section></main>
</template>
